     1→import { Injectable, Logger } from '@nestjs/common';
     2→
     3→import { PromotionalProductsService as DBPromotionalProductsService } from '@modules/db/promotional-products/promotional-products.service';
     4→import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
     5→import { PromotionalProductsResponseDto } from '@modules/rest/promotional-products/dto/promotional-products-response.dto';
     6→import { TrendingProductsService } from '@modules/rest/trending-products/trending-products.service';
     7→
     8→import { shuffleArray } from '@utils/array.util';
     9→import { assignRandomColorToProduct } from '@utils/random-color-picker.util';
    10→
    11→import { IRelatedProduct } from '@interfaces/related-product.interface';
    12→
    13→import { LogExecution } from '@decorators/log-execution.decorator';
    14→
    15→@Injectable()
    16→export class PromotionalProductsService {
    17→	private readonly logger = new Logger(PromotionalProductsService.name);
    18→
    19→	constructor(
    20→		private readonly trendingProductsService: TrendingProductsService,
    21→		private readonly dbPromotionalProductsService: DBPromotionalProductsService,
    22→		private readonly productHydrationService: ProductHydrationService,
    23→	) {}
    24→
    25→	@LogExecution({
    26→		paramFormatter: ([{ categoryId, limit }]: [
    27→			{ categoryId?: number; limit?: number },
    28→		]) => ({
    29→			categoryId,
    30→			limit,
    31→		}),
    32→		responseFormatter: /* istanbul ignore next */ (
    33→			res: PromotionalProductsResponseDto,
    34→		) => ({
    35→			totalCount: res?.totalCount ?? 0,
    36→			trendingCount: res?.trendingCount ?? 0,
    37→			promotionalCount: res?.promotionalCount ?? 0,
    38→		}),
    39→	})
    40→	async getPromotionalProducts({
    41→		categoryId,
    42→		limit = 20,
    43→	}: {
    44→		categoryId?: number | undefined;
    45→		limit?: number | undefined;
    46→	}): Promise<PromotionalProductsResponseDto> {
    47→		this.logger.log('[getPromotionalProducts] Starting promotional products fetch', {
    48→			categoryId: categoryId ?? 'random',
    49→			limit,
    50→		});
    51→
    52→		try {
    53→			const halfLimit = Math.floor(limit / 2);
    54→
    55→			const dbPromotionalProducts = categoryId
    56→				? await this.dbPromotionalProductsService.getProductsByCategory({
    57→						categoryId,
    58→						limit: halfLimit,
    59→					})
    60→				: await this.dbPromotionalProductsService.getRandomProducts(halfLimit);
    61→			this.logger.log('[getPromotionalProducts] DB promotional products fetched', {
    62→				count: dbPromotionalProducts.length,
    63→			});
    64→
    65→			const promotionalProducts: IRelatedProduct[] = [];
    66→
    67→			if (dbPromotionalProducts.length > 0) {
    68→				const styleIds = dbPromotionalProducts.map((p) => p.product_id);
    69→
    70→				try {
    71→					const { products, mvRecords } =
    72→						await this.productHydrationService.hydrateProductsWithColors({
    73→							styleIds,
    74→						});
    75→
    76→					for (const product of products) {
    77→						const mv = mvRecords.get(product.style_id);
    78→						const colors = this.productHydrationService.convertMvColorsToProductColors({
    79→							colors: mv?.colors ?? null,
    80→						});
    81→						const productWithRandomColor = assignRandomColorToProduct(product, colors);
    82→						promotionalProducts.push(productWithRandomColor);
    83→					}
    84→
    85→					this.logger.debug('Hydrated promotional products from MV', {
    86→						hydratedCount: promotionalProducts.length,
    87→						requestedCount: dbPromotionalProducts.length,
    88→					});
    89→				} catch (error) {
    90→					this.logger.error(
    91→						`Error hydrating promotional products from MV: ${(error as Error).message}`,
    92→						(error as Error).stack,
    93→					);
    94→				}
    95→			}
    96→
    97→			const remainingLimit = limit - promotionalProducts.length;
    98→			let trendingProducts: IRelatedProduct[] = [];
    99→
   100→			if (remainingLimit > 0 && categoryId) {
   101→				this.logger.log(
   102→					'[getPromotionalProducts] Filling remaining slots with trending',
   103→					{
   104→						remainingLimit,
   105→						categoryId,
   106→					},
   107→				);
   108→				const trendingResult =
   109→					await this.trendingProductsService.getTrendingProductsByCategory({
   110→						categoryId,
   111→						excludeProductIds: promotionalProducts.map((p) => p.style_id),
   112→						limit: remainingLimit,
   113→					});
   114→				trendingProducts = trendingResult.trendingProducts;
   115→				this.logger.log('[getPromotionalProducts] Trending products fetched', {
   116→					trendingCount: trendingProducts.length,
   117→				});
   118→			}
   119→
   120→			const allProducts = [...trendingProducts, ...promotionalProducts];
   121→			const shuffledProducts = shuffleArray(allProducts);
   122→
   123→			return {
   124→				categoryId: categoryId ?? -1,
   125→				products: shuffledProducts,
   126→				totalCount: shuffledProducts.length,
   127→				trendingCount: trendingProducts.length,
   128→				promotionalCount: promotionalProducts.length,
   129→			};
   130→		} catch (error) {
   131→			this.logger.error(
   132→				`Error fetching promotional products for category ${categoryId ?? 'all'}: ${(error as Error).message}`,
   133→				(error as Error).stack,
   134→			);
   135→			throw error;
   136→		}
   137→	}
   138→}
